VALUES
    (3, '2025-01-04 17:47:21.1325142', 'pagina 2', 2, 1, NULL, 0, 0, '<p style="text-align: center;"><iframe title="ENCONTRANDO UM GIGANTE NA NATUREZA, A BALEIA CINZENTA! | RICHARD RASMUSSEN" src="https://www.youtube.com/embed/r_eLOG096sE" width="320" height="560" frameborder="0" allowfullscreen="allowfullscreen"></iframe></p>', 'Chave', 2, NULL, NULL, NULL),
    (4, '2025-01-04 17:47:21.1378630', 'pagina 3', 2, 1, NULL, 0, 0, '<p>A&nbsp;<strong>baleia-cinzenta</strong>&nbsp;(<em>Eschrichtius robustus</em>) &eacute; um&nbsp;<a class="mw-redirect" title="Mam&iacute;fero" href="https://pt.wikipedia.org/wiki/Mam%C3%ADfero">mam&iacute;fero</a>&nbsp;<a class="mw-redirect" title="Cet&aacute;ceo" href="https://pt.wikipedia.org/wiki/Cet%C3%A1ceo">cet&aacute;ceo</a>&nbsp;da fam&iacute;lia dos&nbsp;<a class="mw-redirect" title="Eschrichtiidae" href="https://pt.wikipedia.org/wiki/Eschrichtiidae">escrict&iacute;deos</a>. &Eacute; a &uacute;nica esp&eacute;cie viva em seu g&ecirc;nero e fam&iacute;lia, mas uma esp&eacute;cie extinta foi descoberta e colocada no g&ecirc;nero em 2017, a&nbsp;<a class="new" title="Baleia Akishima (p&aacute;gina n&atilde;o existe)" href="https://pt.wikipedia.org/w/index.php?title=Baleia_Akishima&amp;action=edit&amp;redlink=1">Baleia Akishima</a>.<sup id="cite_ref-N&atilde;o_nomeado-20230316141054_2-0" class="reference"><a href="https://pt.wikipedia.org/wiki/Baleia-cinzenta#cite_note-N%C3%A3o_nomeado-20230316141054-2">[2]</a></sup></p>
